224Ôćĺ        record.put("vacationSubCode", row[8]);
225Ôćĺ        record.put("vacationSubName", row[9]);
226Ôćĺ
227Ôćĺ        // ŔźőňüçŔÁĚŔĘľŠÖéÚľô´╝łŠá╝ň╝Ćňîľšé║ňşŚńŞ▓´╝ë
228Ôćĺ        LocalDateTime beginTime = toLocalDateTime(row[10]);
229Ôćĺ        LocalDateTime endTime   = toLocalDateTime(row[11]);
