232Ôćĺ
233Ôćĺ        // ŔźőňüçŠÖéŠĽŞ´╝łŠëúÚÖĄňŹłń╝ĹŔĘłš«Ś´╝ë
234Ôćĺ        record.put("leaveHours", calculateLeaveHours(beginTime, endTime));
235Ôćĺ
236Ôćĺ        // š░ŻŠáŞšőÇŠůő
237Ôćĺ        String status = row[12] != null ? row[12].toString().trim() : "";
238Ôćĺ        record.put("leaveStatus", status);
239Ôćĺ
240Ôćĺ        // Šś»ňÉŽňĆ»ÚŐĚňüç´╝łňâů E01:šö│ŔźőńŞş ňĆ»ÚŐĚ´╝ë
241Ôćĺ        record.put("canCancel", "E01".equals(status));
242Ôćĺ
