249Ôćĺ    /**
250Ôćĺ     * ŔĘłš«Śň»ŽÚÜŤŔźőňüçŠÖéŠĽŞ´╝îŠëúÚÖĄŠ»ĆŠŚąňŹłń╝Ĺ´╝ł12:30 ´Ż× 13:30´╝ë
251Ôćĺ     * šÁÉŠ×ťňŤŤŠŹĘń║öňůąŔç│ 0.5 ň░ĆŠÖé´╝łšČŽňÉł TM_VACATION_DETAIL_SETTING.MIN_HOURS š▓żň║Ž´╝ë
252Ôćĺ     *
253Ôćĺ     * @param beginTime ŔźőňüçŔÁĚňžőŠÖéÚľô
254Ôćĺ     * @param endTime   ŔźőňüçšÁÉŠŁčŠÖéÚľô
255Ôćĺ     * @return ň»ŽÚÜŤŠÖéŠĽŞ´╝ł0.5 šé║ŠťÇň░Ćňľ«ńŻŹ´╝ë
256Ôćĺ     */
257Ôćĺ    private double calculateLeaveHours(LocalDateTime beginTime, LocalDateTime endTime) {
258Ôćĺ        if (beginTime == null || endTime == null || !endTime.isAfter(beginTime)) {
259Ôćĺ            return 0.0;
260Ôćĺ        }
261Ôćĺ
262Ôćĺ        long rawMinutes = ChronoUnit.MINUTES.between(beginTime, endTime);
263Ôćĺ        long lunchDeductMinutes = 0;
264Ôćĺ
265Ôćĺ        // ÚÇÉŠŚąŔĘłš«ŚňŹłń╝ĹÚçŹšľŐňłćÚÉśŠĽŞ
266Ôćĺ        LocalDate day     = beginTime.toLocalDate();
267Ôćĺ        LocalDate lastDay = endTime.toLocalDate();
268Ôćĺ
269Ôćĺ        while (!day.isAfter(lastDay)) {
270Ôćĺ            LocalDateTime lunchStart = day.atTime(12, 30);
271Ôćĺ            LocalDateTime lunchEnd   = day.atTime(13, 30);
272Ôćĺ
273Ôćĺ            // ÚçŹšľŐňŹÇÚľô = max(beginTime, lunchStart) ~ min(endTime, lunchEnd)
274Ôćĺ            LocalDateTime overlapStart = beginTime.isAfter(lunchStart) ? beginTime : lunchStart;
275Ôćĺ            LocalDateTime overlapEnd   = endTime.isBefore(lunchEnd)    ? endTime   : lunchEnd;
276Ôćĺ
277Ôćĺ            if (overlapEnd.isAfter(overlapStart)) {
278Ôćĺ                lunchDeductMinutes += ChronoUnit.MINUTES.between(overlapStart, overlapEnd);
279Ôćĺ            }
280Ôćĺ            day = day.plusDays(1);
281Ôćĺ        }
282Ôćĺ
283Ôćĺ        long netMinutes = rawMinutes - lunchDeductMinutes;
284Ôćĺ        // ňŤŤŠŹĘń║öňůąŔç│ 0.5 ň░ĆŠÖé´╝ł30 ňłćÚÉśšé║ňľ«ńŻŹ´╝ë
285Ôćĺ        return Math.round(netMinutes / 30.0) * 0.5;
286Ôćĺ    }
