292Ôćĺ    private String buildOrderBy(String sortBy, String sortOrder) {
293Ôćĺ        String direction = "desc".equalsIgnoreCase(sortOrder) ? "DESC" : "ASC";
294Ôćĺ        String column = switch (sortBy != null ? sortBy : "") {
295Ôćĺ            case "empNameCh"    -> "e.EMP_NAME";
296Ôćĺ            case "deptName"     -> "org.ORG_NAME";
297Ôćĺ            case "vacationName" -> "vs.VACATION_NAME";
298Ôćĺ            case "beginTime"    -> "l.BEGIN_TIME";
299Ôćĺ            case "endTime"      -> "l.END_TIME";
300Ôćĺ            case "leaveStatus"  -> "l.LEAVE_STATUS";
301Ôćĺ            case "leaveHours"   -> "l.BEGIN_TIME"; // ŠÖéŠĽŞšö▒ Java ŔĘłš«Ś´╝îÚÇÇŔÇîń╗ąŔÁĚňžőŠÖéÚľôŠÄĺň║Ć
302Ôćĺ            default             -> "l.BEGIN_TIME";
303Ôćĺ        };
304Ôćĺ        return "ORDER BY " + column + " " + direction + "\n";
305Ôćĺ    }
