    @Override
    protected Object processBusinessLogic(
            Exchange exchange,
            Map<String, Object> payload,
            Map<String, Object> headers,
            String traceId,
            String routeId) throws Exception {

        // 1. ňĆľňżŚšĽÂňëŹšÖ╗ňůąńŻ┐šöĘŔÇů´╝łšö▒ HandlerApiResource Š│ĘňůąŔç│ X-User header´╝ë
        String currentUser = headers.getOrDefault("X-User", "").toString().trim();
        log.debug("[Ŕźőňüçňľ«ŠčąŔęó] Úľőňžő - currentUser: {}, TraceId: {}", currentUser, traceId);

        // 2. ňłĄŠľĚŔžĺŔë▓´╝łADMIN/USER´╝ë
        boolean isAdmin = leaveQueryService.isAdminRole(currentUser);
        log.debug("[Ŕźőňüçňľ«ŠčąŔęó] ŔžĺŔë▓ňłĄŠľĚň«îŠłÉ - isAdmin: {}, TraceId: {}", isAdmin, traceId);

        // 3. ňąŚšöĘÚáÉŔĘşŠčąŔęóŠťčÚľô´╝łňëŹšź»Šť¬ňé│ňůąŠÖéÚáÉŔĘşšé║šĽÂň╣┤ň║Ž´╝ë
        applyDefaultDateRange(payload);

        // 4. ňąŚšöĘÚáÉŔĘşňłćÚáüňĄžň░Ć´╝łŔŽĆŠá╝´╝ÜŠ»ĆÚáü 5 šşć´╝ë
        applyDefaultPerPage(payload);

        // 5. ŔžúŠ×ÉňłćÚáüňĆâŠĽŞ
        PaginationParams paginationParams = PaginationUtil.parsePaginationParams(payload);

        // 6. ňĹ╝ňĆź Service ňčĚŔíîŔĚĘŔíĘŠčąŔęó
        List<Map<String, Object>> records =
                leaveQueryService.queryLeaveList(payload, currentUser, isAdmin);

        log.debug("[Ŕźőňüçňľ«ŠčąŔęó] ŠčąŔęóň«îŠłÉ - šŞŻšşćŠĽŞ: {}, TraceId: {}", records.size(), traceId);

        // 7. ňčĚŔíîŔĘśŠćÂÚźöňłćÚáü
        PaginationResult<Map<String, Object>> result =
                PaginationUtil.paginate(records, paginationParams);

        log.info("[Ŕźőňüçňľ«ŠčąŔęó] ŠłÉňŐč - TotalCount: {}, CurrentPage: {}, PerPage: {}, TraceId: {}",
                result.getTotalCount(), result.getCurrentPage(), paginationParams.getPerPage(), traceId);

        // 8. šÁäŔúŁŠĘÖŠ║ľňŤ×Šçë
        Map<String, Object> response = new HashMap<>(result.toResponseMap("ŠčąŔęóŠłÉňŐč"));
        response.put("traceId", traceId);

        // 9. items Ôćĺ records´╝łšČŽňÉłňëŹšź»Šůúńżő´╝ë
        @SuppressWarnings("unchecked")
        Map<String, Object> data = (Map<String, Object>) response.get("data");
        if (data != null && data.containsKey("items")) {
            Map<String, Object> enhancedData = new HashMap<>(data);
            enhancedData.put("records", enhancedData.remove("items"));
            response.put("data", enhancedData);
        }

        return response;
    }

    // ==================== šžüŠťëŔ╝öňŐęŠľ╣Š│Ľ ====================

    /**
