     */
    private void applyDefaultDateRange(Map<String, Object> payload) {
        int currentYear = LocalDate.now().getYear();
        String defaultBegin = currentYear + "-01-01";
        String defaultEnd   = currentYear + "-12-31";

        Object beginDate = payload.get("beginDate");
        if (beginDate == null || beginDate.toString().trim().isEmpty()
                || "null".equalsIgnoreCase(beginDate.toString().trim())) {
            payload.put("beginDate", defaultBegin);
            log.debug("[Ŕźőňüçňľ«ŠčąŔęó] Šť¬ňé│ňůą beginDate´╝îňąŚšöĘÚáÉŔĘş: {}", defaultBegin);
        }

        Object endDate = payload.get("endDate");
        if (endDate == null || endDate.toString().trim().isEmpty()
                || "null".equalsIgnoreCase(endDate.toString().trim())) {
            payload.put("endDate", defaultEnd);
            log.debug("[Ŕźőňüçňľ«ŠčąŔęó] Šť¬ňé│ňůą endDate´╝îňąŚšöĘÚáÉŔĘş: {}", defaultEnd);
        }
