    /**
     * ŔőąňëŹšź»Šť¬ňé│ňůą perPage´╝îňąŚšöĘŔŽĆŠá╝ÚáÉŔĘşňÇ╝´╝łŠ»ĆÚáü 5 šşć´╝ë
     */
    private void applyDefaultPerPage(Map<String, Object> payload) {
        Object perPage = payload.get("perPage");
        if (perPage == null || perPage.toString().trim().isEmpty()
                || "null".equalsIgnoreCase(perPage.toString().trim())) {
            payload.put("perPage", DEFAULT_PER_PAGE);
        }
    }
