 97Ôćĺ                """);
 98Ôćĺ
 99Ôćĺ        Map<String, Object> params = new LinkedHashMap<>();
100Ôćĺ
101Ôćĺ        // šöčŠĽł/ňĄ▒ŠĽłŠŚąŠťčŠčąŔęó´╝łŠö»ŠĆ┤ň╣┤ń╗ŻŠłľň«îŠĽ┤ŠŚąŠťč´╝ë
102Ôćĺ        if (effectiveDate != null) {
