161Ôćĺ            // šÁÉš«ŚšőÇŠůő´╝ÜMSSQL BIT ŠČäńŻŹňŤ×ňé│šé║ Boolean Šłľ Integer
162Ôćĺ            Object clearVal = row[17];
163Ôćĺ            String settlementStatus = "";
