180Ôćĺ    // ==================== šžüŠťëŔ╝öňŐęŠľ╣Š│Ľ ====================
181Ôćĺ
182Ôćĺ    /**
183Ôćĺ     * ńżŁ sortBy ŠČäńŻŹňÉŹšĘ▒ň╗║šźő ORDER BY ňşÉňĆą
184Ôćĺ     * ÚáÉŔĘşń╗ąňôíňĚąšĚĘŔÖč ASC ŠÄĺň║Ć´╝îŠČíŔŽüŠÄĺň║Ćšé║ňüçňłąń╗úšó╝ ASC
185Ôćĺ     */
186Ôćĺ    private String buildOrderBy(String sortBy, String sortOrder) {
187Ôćĺ        String direction = "desc".equalsIgnoreCase(sortOrder) ? "DESC" : "ASC";
188Ôćĺ        String column = switch (sortBy != null ? sortBy : "") {
189Ôćĺ            case "year"               -> "YEAR(v.BEGIN_DATE)";
190Ôćĺ            case "empNo"              -> "e.EMP_ACCOUNT";
191Ôćĺ            case "empNameCh"          -> "e.EMP_NAME";
192Ôćĺ            case "empNameEn"          -> "e.EMP_NAME_EN";
193Ôćĺ            case "vacationName"       -> "vs.VACATION_NAME";
194Ôćĺ            case "effectiveStartDate" -> "v.BEGIN_DATE";
195Ôćĺ            case "effectiveEndDate"   -> "v.END_DATE";
196Ôćĺ            case "totalHours"         -> "v.MAX_HOURS";
197Ôćĺ            case "usedHours"          -> "v.USED_HOURS";
198Ôćĺ            case "remainingHours"     -> "v.UNUSED_HOURS";
199Ôćĺ            default                  -> "e.EMP_ACCOUNT";
