204Ôćĺ    /**
205Ôćĺ     * ň░çŔ│çŠľÖň║źňŤ×ňé│šÜäŠŚąŠťčšëęń╗ÂŔŻëšé║ yyyy-MM-dd ňşŚńŞ▓
206Ôćĺ     * MSSQL DATE ň×őňłąÚÇĆÚüÄ JDBC ňĆ»ŔâŻňŤ×ňé│šé║ java.sql.Date, java.sql.Timestamp, Šłľ LocalDate
207Ôćĺ     */
208Ôćĺ    private String formatDate(Object dateObj) {
209Ôćĺ        if (dateObj == null) return null;
210Ôćĺ        if (dateObj instanceof java.sql.Date sqlDate) {
211Ôćĺ            return DateFormatUtil.formatDate(sqlDate.toLocalDate());
212Ôćĺ        }
213Ôćĺ        if (dateObj instanceof java.sql.Timestamp timestamp) {
214Ôćĺ            return DateFormatUtil.formatDate(timestamp.toLocalDateTime().toLocalDate());
215Ôćĺ        }
216Ôćĺ        if (dateObj instanceof LocalDateTime localDateTime) {
217Ôćĺ            return DateFormatUtil.formatDate(localDateTime.toLocalDate());
218Ôćĺ        }
219Ôćĺ        if (dateObj instanceof LocalDate localDate) {
220Ôćĺ            return DateFormatUtil.formatDate(localDate);
221Ôćĺ        }
222Ôćĺ        // ŠťÇňżîňśŚŔęŽńŻ┐šöĘ toString´╝îňĆ»ŔâŻÚťÇŔŽüŠł¬ňĆľňëŹ 10 ňÇőňşŚňůâ (yyyy-MM-dd)
223Ôćĺ        String str = dateObj.toString();
224Ôćĺ        if (str.length() >= 10) {
225Ôćĺ            return str.substring(0, 10);
226Ôćĺ        }
227Ôćĺ        return str;
228Ôćĺ    }
