230Ôćĺ    private Integer extractInteger(Map<String, Object> map, String key) {
231Ôćĺ        Object val = map.get(key);
232Ôćĺ        if (val == null) return null;
233Ôćĺ        if (val instanceof Number n) return n.intValue();
234Ôćĺ        String str = val.toString().trim();
235Ôćĺ        if (str.isEmpty()) return null;
236Ôćĺ        try {
237Ôćĺ            return Integer.parseInt(str);
238Ôćĺ        } catch (NumberFormatException e) {
239Ôćĺ            log.warn("[ňôíňĚąňüçňłąŠŞůňľ«] ňĆâŠĽŞ '{}' ňÇ╝ '{}' šäíŠ│ĽŔžúŠ×Éšé║ŠĽ┤ŠĽŞ´╝îňĚ▓ň┐ŻšĽą", key, str);
240Ôćĺ            return null;
241Ôćĺ        }
242Ôćĺ    }
243Ôćĺ
244Ôćĺ    private String extractString(Map<String, Object> map, String key) {
245Ôćĺ        Object val = map.get(key);
246Ôćĺ        if (val == null) return null;
247Ôćĺ        String str = val.toString().trim();
248Ôćĺ        // ÚüÄŠ┐żšę║ňşŚńŞ▓ňĺîňşŚńŞ▓ "null"
249Ôćĺ        if (str.isEmpty() || "null".equalsIgnoreCase(str)) {
250Ôćĺ            return null;
251Ôćĺ        }
252Ôćĺ        return str;
253Ôćĺ    }
