package org.soetek.eap.tm.service;

import io.quarkus.hibernate.orm.PersistenceUnit;
import jakarta.enterprise.context.ApplicationScoped;
import jakarta.inject.Inject;
import jakarta.persistence.EntityManager;
import jakarta.persistence.Query;
import lombok.extern.slf4j.Slf4j;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * TM ŠĘíšÁäňôíňĚąŔ│çŔĘŐŠčąŔęóŠťŹňőÖ
 * <p>
 * ŠĆÉńżŤńżŁňôíňĚąšĚĘŔÖčŠčąŔęóňôíňĚąňč║ŠťČŔ│çŔĘŐšÜäňŐčŔâŻ´╝î
 * ńżŤ TmEmpInfoQueryProcessor ňĺî TmUserOrgQueryProcessor ńŻ┐šöĘŃÇé
 *
 * @author SoeTek Team
 * @since 2026-03-17
 */
@Slf4j
@ApplicationScoped
public class TmEmployeeQueryService {

    @Inject
    @PersistenceUnit("eap")
    EntityManager em;

    /**
     * ńżŁňôíňĚąšĚĘŔÖčŠčąŔęóňôíňĚąňč║ŠťČŔ│çŔĘŐ
     *
     * @param empAccount ňôíňĚąšĚĘŔÖč
     * @return ňôíňĚąŔ│çŔĘŐ Map´╝îŠčąšäíňŤ×ňé│ null
     */
    public Map<String, Object> getEmployeeByAccount(String empAccount) {
        String sql = """
                SELECT
                    e.EMP_ID        AS empId,
                    e.EMP_ACCOUNT   AS empAccount,
                    e.EMP_NAME      AS empName,
                    e.EMP_NAME_EN   AS empNameEn,
                    e.GENDER        AS gender,
                    e.ORG_ID        AS orgId,
                    org.ORG_NAME    AS orgName,
                    e.LEAVE_DATE    AS leaveDate
                FROM EAP.PM_EMPLOYEE e
                LEFT JOIN EAP.AU_ORGANIZATION org ON org.ORG_ID = e.ORG_ID
                WHERE e.EMP_ACCOUNT = :empAccount
                """;

        Query query = em.createNativeQuery(sql);
        query.setParameter("empAccount", empAccount);

        @SuppressWarnings("unchecked")
        List<Object[]> rows = query.getResultList();

        if (rows.isEmpty()) {
            return null;
        }

        Object[] row = rows.get(0);
        Map<String, Object> result = new HashMap<>();
        result.put("empId", row[0]);
        result.put("empAccount", row[1]);
        result.put("empName", row[2]);
        result.put("empNameEn", row[3]);
        result.put("gender", row[4]);
        result.put("orgId", row[5]);
        result.put("orgName", row[6]);
        result.put("leaveDate", row[7]);

        return result;
    }

    /**
     * ńżŁšÖ╗ňůąňŞ│ŔÖčŠčąŔęóńŻ┐šöĘŔÇůšÁäš╣öŔ│çŔĘŐ
     *
     * @param empAccount šÖ╗ňůąňŞ│ŔÖč
     * @return ńŻ┐šöĘŔÇůšÁäš╣öŔ│çŔĘŐ Map´╝îŠčąšäíňŤ×ňé│ null
     */
    public Map<String, Object> getUserOrgInfo(String empAccount) {
        // ňÉî getEmployeeByAccount ńŻćňĆ»Šô┤ňůůŠŤ┤ňĄÜšÁäš╣öŔ│çŔĘŐ
        return getEmployeeByAccount(empAccount);
    }
}

