/**
 * TM002 ňôíňĚąň╣┤ň║ŽňüçňłąÚíŹň║ŽšÂşŔşĚŠťŹňőÖ
 * <p>
 * ŠĆÉńżŤňčĚŔíîÚáÉŔĘşŃÇüŠśÄš┤░ŠčąŔęóŃÇüňä▓ňşśŃÇüňł¬ÚÖĄŃÇüŠë╣ŠČíÚęŚŔşëŃÇüŠë╣ŠČíňî»ňůąšşëňŐčŔâŻŃÇé
 *
 * @author SoeTek Team
 * @since 2026-03-26
 */
@Slf4j
@ApplicationScoped
public class Tm002EmpVacationService {

    @Inject
    @PersistenceUnit("eap")
    EntityManager em;

    /**
     * ňčĚŔíîÚáÉŔĘş ÔÇö ŠčąŔęóšŚůňüçŔĘşň«ÜŔ│çŠľÖ
     * ŠąşňőÖŔŽĆňëç B3´╝ÜňâůňŤ×ňé│šŚůňüç 1 šşć´╝łŠťëŠĽłńŞöŠŚąŠťčňťĘš»äňťŹňůž´╝ë
     */
    public List<Map<String, Object>> getDefaultVacation() {
        String sql = """
                SELECT A.VACATION_CODE, A.VACATION_NAME,
                       B.VACATION_SUB_CODE, B.VACATION_SUB_NAME,
                       B.VACATION_SUB_ID,
                       B.MIN_HOURS, B.MAX_HOURS
                  FROM EAP.TM_VACATION_SETTING A
                  JOIN EAP.TM_VACATION_DETAIL_SETTING B
                    ON A.VACATION_CODE = B.VACATION_CODE
                 WHERE A.VACATION_NAME = N'šŚůňüç'
                   AND GETDATE() BETWEEN B.BEGIN_DATE
                       AND ISNULL(B.END_DATE, CAST('2099-12-31' AS DATE))
                   AND B.IS_EFFECTIVE = 1
                """;

        Query query = em.createNativeQuery(sql);
        @SuppressWarnings("unchecked")
        List<Object[]> rows = query.getResultList();

        List<Map<String, Object>> result = new ArrayList<>();
        for (Object[] row : rows) {
            Map<String, Object> record = new HashMap<>();
            record.put("vacationCode", row[0]);
            record.put("vacationName", row[1]);
            record.put("vacationSubCode", row[2]);
            record.put("vacationSubName", row[3]);
            record.put("vacationSubId", row[4]);
            record.put("minHours", row[5]);
            record.put("maxHours", row[6]);
            result.add(record);
        }
        return result;
    }

    /**
     * ŠčąŔęóňôíňĚąňüçňłąŠśÄš┤░
     */
    public List<Map<String, Object>> queryEmpVacationDetail(Integer empId, int year) {
        String sql = """
                SELECT
                    v.EMP_VACATION_ID,
                    v.EMP_ID,
                    v.VACATION_SUB_ID,
                    vds.VACATION_CODE,
                    vs.VACATION_NAME,
                    vds.VACATION_SUB_CODE,
                    vds.VACATION_SUB_NAME,
                    v.MAX_HOURS,
                    v.USED_HOURS,
                    v.UNUSED_HOURS,
                    v.CASH_OUT_HOURS,
                    v.BEGIN_DATE,
                    v.END_DATE,
                    v.CLEAR
                FROM EAP.TM_EMP_VACATION v
                INNER JOIN EAP.TM_VACATION_DETAIL_SETTING vds
                    ON vds.VACATION_SUB_ID = v.VACATION_SUB_ID
                INNER JOIN EAP.TM_VACATION_SETTING vs
                    ON vs.VACATION_CODE = vds.VACATION_CODE
                WHERE v.EMP_ID = :empId
                  AND YEAR(v.BEGIN_DATE) = :year
                ORDER BY v.VACATION_SUB_ID
                """;

        Query query = em.createNativeQuery(sql);
        query.setParameter("empId", empId);
        query.setParameter("year", year);

        @SuppressWarnings("unchecked")
        List<Object[]> rows = query.getResultList();

        List<Map<String, Object>> result = new ArrayList<>();
        for (Object[] row : rows) {
            Map<String, Object> record = new HashMap<>();
            record.put("empVacationId", row[0]);
            record.put("empId", row[1]);
            record.put("vacationSubId", row[2]);
            record.put("vacationCode", row[3]);
            record.put("vacationName", row[4]);
            record.put("vacationSubCode", row[5]);
            record.put("vacationSubName", row[6]);

            BigDecimal maxHours = toBigDecimal(row[7]);
            BigDecimal usedHours = toBigDecimal(row[8]);
            BigDecimal unusedHours = toBigDecimal(row[9]);

            record.put("maxHours", maxHours);
            record.put("totalHours", maxHours);
            record.put("usedHours", usedHours);
            record.put("unusedHours", unusedHours);
            record.put("remainingHours", unusedHours);
            record.put("cashOutHours", row[10]);
            record.put("beginDate", formatDate(row[11]));
            record.put("endDate", formatDate(row[12]));

            // CLEAR ŠČäńŻŹ ÔÇö šÁÉš«ŚšőÇŠůő
            Object clearVal = row[13];
            boolean isClear = false;
            if (clearVal != null) {
                if (clearVal instanceof Boolean) {
                    isClear = (Boolean) clearVal;
                } else if (clearVal instanceof Number) {
                    isClear = ((Number) clearVal).intValue() == 1;
                }
            }
            record.put("clear", isClear);
            record.put("settlementStatus", isClear ? "Y" : "");

            result.add(record);
        }
        return result;
    }

    /**
     * ňä▓ňşśňôíňĚąňüçňłąŠśÄš┤░´╝łŠľ░ňó× + ń┐«Šö╣´╝ë
     * ŠąşňőÖŔŽĆňëç B1´╝ÜUNUSED_HOURS = MAX_HOURS - USED_HOURS
     * ŠąşňőÖŔŽĆňëç B5´╝ÜńŞŹń┐«Šö╣ CLEAR ŠČäńŻŹ
     */
    @Transactional
    @SuppressWarnings("unchecked")
    public List<Map<String, Object>> saveEmpVacationDetails(Integer empId, List<Map<String, Object>> details) {
        // ÚęŚŔşëňôíňĚąňşśňťĘ
        String checkSql = "SELECT COUNT(*) FROM EAP.PM_EMPLOYEE WHERE EMP_ID = :empId";
        Query checkQuery = em.createNativeQuery(checkSql);
        checkQuery.setParameter("empId", empId);
        Number count = (Number) checkQuery.getSingleResult();
        if (count.intValue() == 0) {
            throw new BusinessException("EMP_NOT_FOUND", 400, "ňôíňĚąńŞŹňşśňťĘ´╝Ü" + empId);
        }

        List<Map<String, Object>> savedRecords = new ArrayList<>();

        for (Map<String, Object> detail : details) {
            Object empVacationIdObj = detail.get("empVacationId");
            Integer vacationSubId = ((Number) detail.get("vacationSubId")).intValue();
            BigDecimal maxHours = toBigDecimal(detail.get("maxHours"));
            BigDecimal usedHours = toBigDecimal(detail.get("usedHours"));
            if (usedHours == null) usedHours = BigDecimal.ZERO;

            // B1: Ŕç¬ňőĽŔĘłš«Ś UNUSED_HOURS
            BigDecimal unusedHours = maxHours.subtract(usedHours);

            String beginDateStr = detail.get("beginDate").toString();
            String endDateStr = detail.get("endDate").toString();
            LocalDate beginDate = LocalDate.parse(beginDateStr);
            LocalDate endDate = LocalDate.parse(endDateStr);

            TmEmpVacationEntity entity;

            if (empVacationIdObj != null) {
                // ń┐«Šö╣ŠĘíň╝Ć
                Integer empVacationId = ((Number) empVacationIdObj).intValue();
                entity = TmEmpVacationEntity.findByKey(empVacationId);
                if (entity == null) {
                    throw new BusinessException("RECORD_NOT_FOUND", 400, "ŔĘśÚîäńŞŹňşśňťĘ´╝Ü" + empVacationId);
                }
                // B5: ńŞŹń┐«Šö╣ CLEAR ŠČäńŻŹ ÔÇö ń┐ŁšĽÖňÄčňÇ╝
                entity.vacationSubId = vacationSubId;
                entity.maxHours = maxHours;
                entity.usedHours = usedHours;
                entity.unusedHours = unusedHours;
                entity.beginDate = beginDate;
                entity.endDate = endDate;
            } else {
                // Šľ░ňó×ŠĘíň╝Ć
                entity = new TmEmpVacationEntity();
                entity.empId = empId;
                entity.vacationSubId = vacationSubId;
                entity.maxHours = maxHours;
                entity.usedHours = usedHours;
                entity.unusedHours = unusedHours;
                entity.cashOutHours = BigDecimal.ZERO;
                entity.beginDate = beginDate;
                entity.endDate = endDate;
                entity.clear = false;
                entity.persist();
            }

            Map<String, Object> saved = new HashMap<>();
            saved.put("empVacationId", entity.empVacationId);
            saved.put("empId", entity.empId);
            saved.put("vacationSubId", entity.vacationSubId);
            saved.put("maxHours", entity.maxHours);
            saved.put("usedHours", entity.usedHours);
            saved.put("unusedHours", entity.unusedHours);
            saved.put("beginDate", DateFormatUtil.formatDate(entity.beginDate));
            saved.put("endDate", DateFormatUtil.formatDate(entity.endDate));
            savedRecords.add(saved);
        }

        em.flush();
        return savedRecords;
    }

    /**
     * ňł¬ÚÖĄňôíňĚąňüçňłąŠśÄš┤░´╝łšíČňł¬ÚÖĄ´╝ë
     * ŠąşňőÖŔŽĆňëç B4´╝ÜšÁÉš«ŚňłŚ´╝łCLEAR=1´╝ëńŞŹňĆ»ňł¬ÚÖĄ
     * ŠąşňőÖŔŽĆňëç B6´╝ÜÚŁ×šÁÉš«ŚňłŚšíČňł¬ÚÖĄ´╝łDELETE FROM´╝ë
     */
    @Transactional
    public void deleteEmpVacation(Integer empVacationId) {
        TmEmpVacationEntity entity = TmEmpVacationEntity.findByKey(empVacationId);
        if (entity == null) {
            throw new BusinessException("RECORD_NOT_FOUND", 400, "ŔĘśÚîäńŞŹňşśňťĘ´╝Ü" + empVacationId);
        }

        // B4: šÁÉš«ŚňłŚńŞŹňĆ»ňł¬ÚÖĄ
        if (Boolean.TRUE.equals(entity.clear)) {
            throw new BusinessException("CLEAR_CANNOT_DELETE", 400, "šÁÉš«ŚŔĘśÚîäńŞŹňĆ»ňł¬ÚÖĄ");
        }

        // B6: šíČňł¬ÚÖĄ
        entity.delete();
        em.flush();
    }

    /**
     * Šë╣ŠČíÚęŚŔşëňôíňĚą
     * ŠąşňőÖŔŽĆňëç B10´╝Ü
     * - ňťĘŔüĚ Ôćĺ ŠťëŠĽł
     * - ňĚ▓ÚŤóŔüĚ Ôćĺ ŃÇîňôíňĚąňĚ▓ÚŤóŔüĚŃÇŹ
     * - ŠčąńŞŹňł░ Ôćĺ ŃÇîŠčąšäíŠşĄňôíňĚąŃÇŹ
     */
    public List<Map<String, Object>> validateEmployees(List<String> empAccounts) {
        List<Map<String, Object>> results = new ArrayList<>();

        for (String empAccount : empAccounts) {
            Map<String, Object> result = new HashMap<>();
            result.put("empAccount", empAccount);

            String sql = """
                    SELECT e.EMP_ID, e.EMP_NAME, e.ORG_ID, e.LEAVE_DATE,
                           org.ORG_NAME
                    FROM EAP.PM_EMPLOYEE e
                    LEFT JOIN EAP.AU_ORGANIZATION org ON org.ORG_ID = e.ORG_ID
                    WHERE e.EMP_ACCOUNT = :empAccount
                    """;
            Query query = em.createNativeQuery(sql);
            query.setParameter("empAccount", empAccount);

            @SuppressWarnings("unchecked")
            List<Object[]> rows = query.getResultList();

            if (rows.isEmpty()) {
                result.put("valid", false);
                result.put("errorMessage", "ŠčąšäíŠşĄňôíňĚą");
            } else {
                Object[] row = rows.get(0);
                Object leaveDate = row[3];
                boolean isResigned = leaveDate != null;

                if (isResigned) {
                    result.put("valid", false);
                    result.put("errorMessage", "ňôíňĚąňĚ▓ÚŤóŔüĚ");
                } else {
                    result.put("valid", true);
                    result.put("empId", row[0]);
                    result.put("empName", row[1]);
                    result.put("orgId", row[2]);
                    result.put("orgName", row[4]);
                }
            }

            results.add(result);
        }

        return results;
    }

    /**
     * Šë╣ŠČíňî»ňůąň╗║šźő
     * ŠąşňőÖŔŽĆňëç B1´╝ÜUNUSED_HOURS = MAX_HOURS - 0´╝łŠľ░ň╗║ňĚ▓šöĘšé║ 0´╝ë
     * ŠąşňőÖŔŽĆňëç B11´╝ÜšÁÉŠŁčŠŚąńŞŹňĆ»ŠŚęŠľ╝ŔÁĚňžőŠŚą
     */
    @Transactional
    @SuppressWarnings("unchecked")
    public int batchImport(Map<String, Object> payload) {
        // ÚęŚŔşëň┐ůňíź
        Object empIdsObj = payload.get("empIds");
        Object vacSubIdObj = payload.get("vacationSubId");
        Object maxHoursObj = payload.get("maxHours");
        Object beginDateObj = payload.get("beginDate");
        Object endDateObj = payload.get("endDate");

        if (empIdsObj == null || !(empIdsObj instanceof List) || ((List<?>) empIdsObj).isEmpty()) {
            throw new BusinessException("REQUIRED_FIELD", 400, "empIds šé║ň┐ůňíźŠČäńŻŹ");
        }
        if (vacSubIdObj == null) {
            throw new BusinessException("REQUIRED_FIELD", 400, "vacationSubId šé║ň┐ůňíźŠČäńŻŹ");
        }
        if (maxHoursObj == null) {
            throw new BusinessException("REQUIRED_FIELD", 400, "maxHours šé║ň┐ůňíźŠČäńŻŹ");
        }
        if (beginDateObj == null) {
            throw new BusinessException("REQUIRED_FIELD", 400, "beginDate šé║ň┐ůňíźŠČäńŻŹ");
        }
        if (endDateObj == null) {
            throw new BusinessException("REQUIRED_FIELD", 400, "endDate šé║ň┐ůňíźŠČäńŻŹ");
        }

        List<Number> empIds = (List<Number>) empIdsObj;
        Integer vacationSubId = ((Number) vacSubIdObj).intValue();
        BigDecimal maxHours = toBigDecimal(maxHoursObj);
        LocalDate beginDate = LocalDate.parse(beginDateObj.toString());
        LocalDate endDate = LocalDate.parse(endDateObj.toString());

        // B11: šÁÉŠŁčŠŚąńŞŹňĆ»ŠŚęŠľ╝ŔÁĚňžőŠŚą
        if (endDate.isBefore(beginDate)) {
            throw new BusinessException("DATE_INVALID", 400, "šÁÉŠŁčŠŚąńŞŹňĆ»ŠŚęŠľ╝ŔÁĚňžőŠŚą");
        }

        // ÚęŚŔşëňüçňłąš┤░ÚáůňşśňťĘ
        String checkSql = "SELECT COUNT(*) FROM EAP.TM_VACATION_DETAIL_SETTING WHERE VACATION_SUB_ID = :vacSubId";
        Query checkQuery = em.createNativeQuery(checkSql);
        checkQuery.setParameter("vacSubId", vacationSubId);
        Number checkCount = (Number) checkQuery.getSingleResult();
        if (checkCount.intValue() == 0) {
            throw new BusinessException("VAC_SUB_NOT_FOUND", 400, "ňüçňłąš┤░ÚáůńŞŹňşśňťĘ´╝Ü" + vacationSubId);
        }

        // B1: UNUSED = MAX - 0
        BigDecimal unusedHours = maxHours;

        int createdCount = 0;
        for (Number empIdNum : empIds) {
            Integer empId = empIdNum.intValue();

            TmEmpVacationEntity entity = new TmEmpVacationEntity();
            entity.empId = empId;
            entity.vacationSubId = vacationSubId;
            entity.maxHours = maxHours;
            entity.usedHours = BigDecimal.ZERO;
            entity.unusedHours = unusedHours;
            entity.cashOutHours = BigDecimal.ZERO;
            entity.beginDate = beginDate;
            entity.endDate = endDate;
            entity.clear = false;
            entity.persist();
            createdCount++;
        }

        em.flush();
        return createdCount;
    }

    // ==================== šžüŠťëŔ╝öňŐęŠľ╣Š│Ľ ====================

    private BigDecimal toBigDecimal(Object obj) {
        if (obj == null) return null;
        if (obj instanceof BigDecimal) return (BigDecimal) obj;
        if (obj instanceof Number) return BigDecimal.valueOf(((Number) obj).doubleValue());
        try {
            return new BigDecimal(obj.toString().trim());
        } catch (NumberFormatException e) {
            return null;
        }
    }

    private String formatDate(Object dateObj) {
        if (dateObj == null) return null;
        if (dateObj instanceof java.sql.Date sqlDate) {
            return DateFormatUtil.formatDate(sqlDate.toLocalDate());
        }
        if (dateObj instanceof java.sql.Timestamp timestamp) {
            return DateFormatUtil.formatDate(timestamp.toLocalDateTime().toLocalDate());
        }
        if (dateObj instanceof LocalDateTime localDateTime) {
            return DateFormatUtil.formatDate(localDateTime.toLocalDate());
        }
        if (dateObj instanceof LocalDate localDate) {
            return DateFormatUtil.formatDate(localDate);
        }
        String str = dateObj.toString();
        if (str.length() >= 10) {
            return str.substring(0, 10);
        }
        return str;
    }
}

