391Ôćĺ    private BigDecimal toBigDecimal(Object obj) {
392Ôćĺ        if (obj == null) return null;
393Ôćĺ        if (obj instanceof BigDecimal) return (BigDecimal) obj;
394Ôćĺ        if (obj instanceof Number) return BigDecimal.valueOf(((Number) obj).doubleValue());
395Ôćĺ        try {
396Ôćĺ            return new BigDecimal(obj.toString().trim());
397Ôćĺ        } catch (NumberFormatException e) {
398Ôćĺ            return null;
399Ôćĺ        }
400Ôćĺ    }
