402Ôćĺ    private String formatDate(Object dateObj) {
403Ôćĺ        if (dateObj == null) return null;
404Ôćĺ        if (dateObj instanceof java.sql.Date sqlDate) {
405Ôćĺ            return DateFormatUtil.formatDate(sqlDate.toLocalDate());
406Ôćĺ        }
407Ôćĺ        if (dateObj instanceof java.sql.Timestamp timestamp) {
408Ôćĺ            return DateFormatUtil.formatDate(timestamp.toLocalDateTime().toLocalDate());
409Ôćĺ        }
410Ôćĺ        if (dateObj instanceof LocalDateTime localDateTime) {
411Ôćĺ            return DateFormatUtil.formatDate(localDateTime.toLocalDate());
412Ôćĺ        }
413Ôćĺ        if (dateObj instanceof LocalDate localDate) {
414Ôćĺ            return DateFormatUtil.formatDate(localDate);
415Ôćĺ        }
416Ôćĺ        String str = dateObj.toString();
417Ôćĺ        if (str.length() >= 10) {
418Ôćĺ            return str.substring(0, 10);
419Ôćĺ        }
420Ôćĺ        return str;
421Ôćĺ    }
