 74Ôćĺ                    org.ORG_ID              AS deptCode,
 75Ôćĺ                    org.ORG_NAME            AS deptName,
 76Ôćĺ                    vds.VACATION_CODE       AS vacationCode,
 77Ôćĺ                    vs.VACATION_NAME        AS vacationName,
 78Ôćĺ                    vds.VACATION_SUB_CODE   AS vacationSubCode,
 79Ôćĺ                    vds.VACATION_SUB_NAME   AS vacationSubName,
 80Ôćĺ                    v.BEGIN_DATE            AS effectiveStartDate,
 81Ôćĺ                    v.END_DATE              AS effectiveEndDate,
 82Ôćĺ                    v.MAX_HOURS             AS totalHours,
 83Ôćĺ                    v.USED_HOURS            AS usedHours,
 84Ôćĺ                    v.UNUSED_HOURS          AS remainingHours,
 85Ôćĺ                    v.CLEAR                 AS settlementStatus,
 86Ôćĺ                    v.CASH_OUT_HOURS        AS cashOutHours
 87Ôćĺ                FROM EAP.TM_EMP_VACATION v
 88Ôćĺ                INNER JOIN EAP.PM_EMPLOYEE e
 89Ôćĺ                    ON e.EMP_ID = v.EMP_ID
 90Ôćĺ                LEFT JOIN EAP.AU_ORGANIZATION org
 91Ôćĺ                    ON org.ORG_ID = e.ORG_ID
 92Ôćĺ                INNER JOIN EAP.TM_VACATION_DETAIL_SETTING vds
 93Ôćĺ                    ON vds.VACATION_SUB_ID = v.VACATION_SUB_ID
 94Ôćĺ                INNER JOIN EAP.TM_VACATION_SETTING vs
 95Ôćĺ                    ON vs.VACATION_CODE = vds.VACATION_CODE
 96Ôćĺ                WHERE (e.LEAVE_DATE IS NULL OR e.LEAVE_DATE >= GETDATE())
 97Ôćĺ                """);
 98Ôćĺ
 99Ôćĺ        Map<String, Object> params = new LinkedHashMap<>();
100Ôćĺ
101Ôćĺ        // šöčŠĽł/ňĄ▒ŠĽłŠŚąŠťčŠčąŔęó´╝łŠö»ŠĆ┤ň╣┤ń╗ŻŠłľň«îŠĽ┤ŠŚąŠťč´╝ë
102Ôćĺ        if (effectiveDate != null) {
103Ôćĺ            if (effectiveDate.matches("^\\d{4}$")) {
104Ôćĺ                // š┤öň╣┤ń╗Ż´╝Üš»ęÚüŞ BEGIN_DATE ň╣┤ń╗ŻšşëŠľ╝Ŕ╝ŞňůąňÇ╝
105Ôćĺ                sql.append("  AND YEAR(v.BEGIN_DATE) = :year\n");
106Ôćĺ                params.put("year", Integer.parseInt(effectiveDate));
107Ôćĺ            } else if (effectiveDate.matches("^\\d{4}-\\d{2}-\\d{2}$")) {
108Ôćĺ                // ň«îŠĽ┤ŠŚąŠťč´╝Üš»ęÚüŞŔę▓ŠŚąŠťčŔÉŻňťĘ BEGIN_DATE ~ END_DATE ňŹÇÚľôňůž
109Ôćĺ                sql.append("  AND v.BEGIN_DATE <= :effectiveDate\n");
110Ôćĺ                sql.append("  AND v.END_DATE >= :effectiveDate\n");
111Ôćĺ                params.put("effectiveDate", LocalDate.parse(effectiveDate));
112Ôćĺ            }
