114Ôćĺ
115Ôćĺ        if (deptCode != null) {
116Ôćĺ            sql.append("  AND e.ORG_ID = :deptCode\n");
117Ôćĺ            params.put("deptCode", deptCode);
118Ôćĺ        }
119Ôćĺ
120Ôćĺ        if (empNo != null) {
121Ôćĺ            sql.append("  AND e.EMP_ACCOUNT LIKE :empNo\n");
122Ôćĺ            params.put("empNo", "%" + empNo + "%");
123Ôćĺ        }
124Ôćĺ
125Ôćĺ        if (empName != null) {
126Ôćĺ            sql.append("  AND e.EMP_NAME LIKE :empName\n");
127Ôćĺ            params.put("empName", "%" + empName + "%");
128Ôćĺ        }
129Ôćĺ
130Ôćĺ        sql.append(buildOrderBy(sortBy, sortOrder));
131Ôćĺ
132Ôćĺ        log.debug("[ňôíňĚąňüçňłąŠŞůňľ«] ŠčąŔęóŠóŁń╗Â - effectiveDate:{}, deptCode:{}, empNo:{}, empName:{}",
133Ôćĺ                effectiveDate, deptCode, empNo, empName);
134Ôćĺ
135Ôćĺ        Query query = em.createNativeQuery(sql.toString());
136Ôćĺ        params.forEach(query::setParameter);
137Ôćĺ
138Ôćĺ        @SuppressWarnings("unchecked")
139Ôćĺ        List<Object[]> rows = query.getResultList();
140Ôćĺ
141Ôćĺ        List<Map<String, Object>> result = new ArrayList<>(rows.size());
142Ôćĺ        for (Object[] row : rows) {
143Ôćĺ            Map<String, Object> record = new HashMap<>();
144Ôćĺ            record.put("quotaId",            row[0]);
145Ôćĺ            record.put("empId",              row[1]);
146Ôćĺ            record.put("year",               row[2]);
147Ôćĺ            record.put("empNo",              row[3]);
148Ôćĺ            record.put("empNameCh",          row[4]);
149Ôćĺ            record.put("empNameEn",          row[5]);
150Ôćĺ            record.put("deptCode",           row[6]);
151Ôćĺ            record.put("deptName",           row[7]);
152Ôćĺ            record.put("vacationCode",       row[8]);
153Ôćĺ            record.put("vacationName",       row[9]);
154Ôćĺ            record.put("vacationSubCode",    row[10]);
155Ôćĺ            record.put("vacationSubName",    row[11]);
156Ôćĺ            record.put("effectiveStartDate", formatDate(row[12]));
157Ôćĺ            record.put("effectiveEndDate",   formatDate(row[13]));
158Ôćĺ            record.put("totalHours",         row[14]);
159Ôćĺ            record.put("usedHours",          row[15]);
160Ôćĺ            record.put("remainingHours",     row[16]);
161Ôćĺ            // šÁÉš«ŚšőÇŠůő´╝ÜMSSQL BIT ŠČäńŻŹňŤ×ňé│šé║ Boolean Šłľ Integer
162Ôćĺ            Object clearVal = row[17];
163Ôćĺ            String settlementStatus = "";
164Ôćĺ            if (clearVal != null) {
165Ôćĺ                if (clearVal instanceof Boolean) {
166Ôćĺ                    settlementStatus = (Boolean) clearVal ? "Y" : "";
167Ôćĺ                } else if (clearVal instanceof Number) {
168Ôćĺ                    settlementStatus = ((Number) clearVal).intValue() == 1 ? "Y" : "";
169Ôćĺ                }
