174Ôćĺ        }
175Ôćĺ
176Ôćĺ        log.debug("[ňôíňĚąňüçňłąŠŞůňľ«] ŠčąŔęóň«îŠłÉ´╝îňů▒ {} šşć", result.size());
177Ôćĺ        return result;
178Ôćĺ    }
179Ôćĺ
180Ôćĺ    // ==================== šžüŠťëŔ╝öňŐęŠľ╣Š│Ľ ====================
181Ôćĺ
182Ôćĺ    /**
183Ôćĺ     * ńżŁ sortBy ŠČäńŻŹňÉŹšĘ▒ň╗║šźő ORDER BY ňşÉňĆą
184Ôćĺ     * ÚáÉŔĘşń╗ąňôíňĚąšĚĘŔÖč ASC ŠÄĺň║Ć´╝îŠČíŔŽüŠÄĺň║Ćšé║ňüçňłąń╗úšó╝ ASC
185Ôćĺ     */
186Ôćĺ    private String buildOrderBy(String sortBy, String sortOrder) {
187Ôćĺ        String direction = "desc".equalsIgnoreCase(sortOrder) ? "DESC" : "ASC";
188Ôćĺ        String column = switch (sortBy != null ? sortBy : "") {
189Ôćĺ            case "year"               -> "YEAR(v.BEGIN_DATE)";
190Ôćĺ            case "empNo"              -> "e.EMP_ACCOUNT";
191Ôćĺ            case "empNameCh"          -> "e.EMP_NAME";
192Ôćĺ            case "empNameEn"          -> "e.EMP_NAME_EN";
193Ôćĺ            case "vacationName"       -> "vs.VACATION_NAME";
194Ôćĺ            case "effectiveStartDate" -> "v.BEGIN_DATE";
195Ôćĺ            case "effectiveEndDate"   -> "v.END_DATE";
196Ôćĺ            case "totalHours"         -> "v.MAX_HOURS";
197Ôćĺ            case "usedHours"          -> "v.USED_HOURS";
198Ôćĺ            case "remainingHours"     -> "v.UNUSED_HOURS";
199Ôćĺ            default                  -> "e.EMP_ACCOUNT";
200Ôćĺ        };
201Ôćĺ        return "ORDER BY " + column + " " + direction + ", vds.VACATION_CODE ASC\n";
202Ôćĺ    }
203Ôćĺ
204Ôćĺ    /**
205Ôćĺ     * ň░çŔ│çŠľÖň║źňŤ×ňé│šÜäŠŚąŠťčšëęń╗ÂŔŻëšé║ yyyy-MM-dd ňşŚńŞ▓
206Ôćĺ     * MSSQL DATE ň×őňłąÚÇĆÚüÄ JDBC ňĆ»ŔâŻňŤ×ňé│šé║ java.sql.Date, java.sql.Timestamp, Šłľ LocalDate
207Ôćĺ     */
208Ôćĺ    private String formatDate(Object dateObj) {
209Ôćĺ        if (dateObj == null) return null;
210Ôćĺ        if (dateObj instanceof java.sql.Date sqlDate) {
211Ôćĺ            return DateFormatUtil.formatDate(sqlDate.toLocalDate());
212Ôćĺ        }
213Ôćĺ        if (dateObj instanceof java.sql.Timestamp timestamp) {
214Ôćĺ            return DateFormatUtil.formatDate(timestamp.toLocalDateTime().toLocalDate());
215Ôćĺ        }
216Ôćĺ        if (dateObj instanceof LocalDateTime localDateTime) {
217Ôćĺ            return DateFormatUtil.formatDate(localDateTime.toLocalDate());
218Ôćĺ        }
219Ôćĺ        if (dateObj instanceof LocalDate localDate) {
220Ôćĺ            return DateFormatUtil.formatDate(localDate);
221Ôćĺ        }
222Ôćĺ        // ŠťÇňżîňśŚŔęŽńŻ┐šöĘ toString´╝îňĆ»ŔâŻÚťÇŔŽüŠł¬ňĆľňëŹ 10 ňÇőňşŚňůâ (yyyy-MM-dd)
223Ôćĺ        String str = dateObj.toString();
224Ôćĺ        if (str.length() >= 10) {
225Ôćĺ            return str.substring(0, 10);
226Ôćĺ        }
227Ôćĺ        return str;
228Ôćĺ    }
229Ôćĺ
230Ôćĺ    private Integer extractInteger(Map<String, Object> map, String key) {
231Ôćĺ        Object val = map.get(key);
232Ôćĺ        if (val == null) return null;
233Ôćĺ        if (val instanceof Number n) return n.intValue();
234Ôćĺ        String str = val.toString().trim();
235Ôćĺ        if (str.isEmpty()) return null;
236Ôćĺ        try {
237Ôćĺ            return Integer.parseInt(str);
238Ôćĺ        } catch (NumberFormatException e) {
239Ôćĺ            log.warn("[ňôíňĚąňüçňłąŠŞůňľ«] ňĆâŠĽŞ '{}' ňÇ╝ '{}' šäíŠ│ĽŔžúŠ×Éšé║ŠĽ┤ŠĽŞ´╝îňĚ▓ň┐ŻšĽą", key, str);
240Ôćĺ            return null;
241Ôćĺ        }
242Ôćĺ    }
243Ôćĺ
244Ôćĺ    private String extractString(Map<String, Object> map, String key) {
245Ôćĺ        Object val = map.get(key);
246Ôćĺ        if (val == null) return null;
247Ôćĺ        String str = val.toString().trim();
248Ôćĺ        // ÚüÄŠ┐żšę║ňşŚńŞ▓ňĺîňşŚńŞ▓ "null"
249Ôćĺ        if (str.isEmpty() || "null".equalsIgnoreCase(str)) {
250Ôćĺ            return null;
251Ôćĺ        }
252Ôćĺ        return str;
253Ôćĺ    }
254Ôćĺ}
