async function handleFileUpload(file: File | null) {
  if (!file) return

  let empAccounts: string[] = []
  const fileName = file.name.toLowerCase()

  if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls')) {
    // XLSX: ńŻ┐šöĘ SheetJS ŔžúŠ×É
    const buffer = await file.arrayBuffer()
    const workbook = XLSX.read(buffer, { type: 'array' })
    const sheet = workbook.Sheets[workbook.SheetNames[0]]
    const rows = XLSX.utils.sheet_to_json<string[]>(sheet, { header: 1 })
    // ŔĚ│ÚüÄŠĘÖÚíîňłŚ´╝îňĆľšČČńŞÇŠČä
    empAccounts = rows.slice(1)
      .map(row => (row[0] != null ? String(row[0]).trim() : ''))
      .filter(v => v.length > 0)
  } else {
    // CSV: ŔÖĽšÉć BOMŃÇü\r\n ŠĆŤŔíîŃÇüšę║šÖŻŔíî
    let text = await file.text()
    // šž╗ÚÖĄ BOM
    if (text.charCodeAt(0) === 0xFEFF) {
      text = text.substring(1)
    }
    const lines = text.split(/\r?\n/).map(l => l.trim()).filter(l => l.length > 0)
    // ŔĚ│ÚüÄŠĘÖÚíîňłŚ
    empAccounts = lines.slice(1)
  }

  if (empAccounts.length > 0) {
    await store.batchValidate(empAccounts)
  }
}

