function validateDetails(): boolean {
  for (const row of details.value) {
    if (!row.vacationSubId) {
      $q.notify({ type: 'warning', message: t('tm002.validation.vacationSubIdRequired') })
      return false
    }
    if (!row.maxHours || row.maxHours <= 0) {
      $q.notify({ type: 'warning', message: t('tm002.validation.maxHoursPositive') })
      return false
    }
    if (!row.beginDate) {
      $q.notify({ type: 'warning', message: t('tm002.validation.beginDateRequired') })
      return false
    }
    if (!row.endDate) {
      $q.notify({ type: 'warning', message: t('tm002.validation.endDateRequired') })
      return false
    }
    if (row.endDate < row.beginDate) {
      $q.notify({ type: 'warning', message: t('tm002.validation.endDateBeforeBeginDate') })
      return false
    }
  }
  return true
}

async function handleSave() {
  if (!props.rowData) return
  if (!validateDetails()) return
  await store.saveDetails({
    empId: props.rowData.empId,
    details: details.value.map(d => ({
      empVacationId: d.empVacationId,
      vacationSubId: d.vacationSubId,
      maxHours: d.maxHours,
      usedHours: d.usedHours,
      beginDate: d.beginDate,
      endDate: d.endDate
    }))
  })
  emit('saved')
  dialogVisible.value = false
}
